//! # Decoder — QuantBlock → DenseTensor on the standing-wave subspace
//!
//! Inverse of `encoder.rs`. Mirrors the Lean
//! `ResonanceKnotDecoder.decode_block` and `dequantize_value` functions
//! (`open-source/gnosis-math/Gnosis/ResonanceKnotDecoder.lean`).
//!
//! Two structural guarantees mirror Lean theorems:
//!
//! - `decode_block_zero_off_standing` — every `(i, j)` outside
//!   `standing × standing` decodes to exactly `0.0`. This is the
//!   compression guarantee: the off-standing entries cost zero bytes
//!   on disk because they are reconstructed by initialization.
//! - `dequantize_value` is the linear inverse of `encoder::quantize_value`
//!   on the lattice `{0, 1, …, 2^bits − 1}` so the round-trip error is
//!   bounded by one quantization step.

use std::borrow::Cow;

use super::bitwise_fp48::{fp48_unpack, Fp48Packed};
use super::encoder::{
    graded_header_len, row_scale_for_width, signed_bias, GRADED_MAX_BITS, GRADED_MIN_BITS,
    SCALE_PREFIX_LEN,
};
use super::format::{DenseTensor, QuantBlock, SpectralManifest};

/// On-disk payloads written by `encode-rknot --apply-fp48` are
/// `serde_json::to_vec(&{codebook, indices, literals, original_byte_len})`.
/// Detect that shape and unpack back to the raw `[scale || codes]`
/// bytes the decoder expects. Pre-fp48 payloads start with a non-`{`
/// byte (the f32 scale's first byte) and are returned unchanged.
fn unwrap_fp48_json(payload: &[u8]) -> Cow<'_, [u8]> {
    if payload.first() != Some(&b'{') {
        return Cow::Borrowed(payload);
    }
    #[derive(serde::Deserialize)]
    struct Wire {
        codebook: Vec<Vec<u8>>,
        indices: Vec<u8>,
        literals: Vec<u8>,
        original_byte_len: u32,
    }
    let parsed: Wire = match serde_json::from_slice(payload) {
        Ok(p) => p,
        Err(_) => return Cow::Borrowed(payload),
    };
    let codebook: Vec<[u8; 8]> = parsed
        .codebook
        .into_iter()
        .filter_map(|w| <[u8; 8]>::try_from(w).ok())
        .collect();
    let packed = Fp48Packed {
        codebook,
        indices: parsed.indices,
        literals: parsed.literals,
        original_byte_len: parsed.original_byte_len,
    };
    Cow::Owned(fp48_unpack(&packed))
}

/// Inverse of `encoder::quantize_signed`: returns
/// `((code as i32) - 2^(bits-1)) * scale`.
///
/// `bits == 0` decodes to `0.0` (matches encoder's zero-bits
/// convention).
pub fn dequantize_signed(code: u32, bits: u8, scale: f32) -> f32 {
    if bits == 0 {
        return 0.0;
    }
    let bias = signed_bias(bits);
    let mask: u32 = if bits >= 31 {
        0xffff_ffff
    } else {
        (1u32 << bits) - 1
    };
    let signed_code = (code & mask) as i32 - bias;
    signed_code as f32 * scale
}

/// Read the per-block `f32` scale from the first 4 bytes of `payload`.
/// Returns `1.0` if the payload is too short or the bytes don't decode
/// to a finite positive number (defensive: a zero / NaN scale would
/// silently kill all reconstruction signal).
pub(super) fn read_block_scale(payload: &[u8]) -> f32 {
    if payload.len() < SCALE_PREFIX_LEN {
        return 1.0;
    }
    let bytes: [u8; 4] = [payload[0], payload[1], payload[2], payload[3]];
    let s = f32::from_le_bytes(bytes);
    if s.is_finite() && s > 0.0 {
        s
    } else {
        1.0
    }
}

/// Inverse of `encoder::pack_codes`. Same LSB-first convention: the
/// `bits`-wide code at index `i` lives at bit position `i * bits` in
/// the byte buffer, low byte first, low bit first within each byte.
fn unpack_codes(packed: &[u8], bits: u8, count: usize) -> Vec<u32> {
    if bits == 0 || count == 0 {
        return vec![0u32; count];
    }
    let mut out = Vec::with_capacity(count);
    let mask = (1u64 << bits) - 1;
    for i in 0..count {
        let bit_pos = i * bits as usize;
        let byte_idx = bit_pos / 8;
        let bit_offset = bit_pos % 8;
        // Pull up to 5 bytes (enough for any bits ≤ 31 + 7 bit offset = 38 bits).
        let mut acc: u64 = 0;
        for b in 0..5 {
            if byte_idx + b < packed.len() {
                acc |= (packed[byte_idx + b] as u64) << (8 * b);
            }
        }
        let code = ((acc >> bit_offset) & mask) as u32;
        out.push(code);
    }
    out
}

/// Decode a quantized block back into a dense `manifest.d × manifest.d`
/// tensor. Walks `(local_row, local_col) ∈ [0, k) × [0, k)`, unpacks the
/// matching code, dequantizes, and writes to the global position
/// `(standing_indices[local_row], standing_indices[local_col])`.
/// Off-standing entries stay `0.0`.
///
/// Mirrors Lean `decode_block` and `decode_block_zero_off_standing`.
pub fn decode_block(block: &QuantBlock, manifest: &SpectralManifest) -> DenseTensor {
    debug_assert!(manifest.is_well_formed());
    let d = manifest.d as usize;
    let k = manifest.k as usize;
    let mut data = vec![0.0f32; d * d];
    let payload = unwrap_fp48_json(&block.payload);
    let scale = read_block_scale(&payload);
    let body = if payload.len() >= SCALE_PREFIX_LEN {
        &payload[SCALE_PREFIX_LEN..]
    } else {
        &[][..]
    };
    let codes = unpack_codes(body, block.bits_per_entry, k * k);
    for local_row in 0..k {
        let global_row = manifest.standing_indices[local_row] as usize;
        if global_row >= d {
            continue;
        }
        let row_base_local = local_row * k;
        let row_base_global = global_row * d;
        for local_col in 0..k {
            let global_col = manifest.standing_indices[local_col] as usize;
            if global_col >= d {
                continue;
            }
            let code = codes[row_base_local + local_col];
            data[row_base_global + global_col] =
                dequantize_signed(code, block.bits_per_entry, scale);
        }
    }
    DenseTensor {
        rows: manifest.d,
        cols: manifest.d,
        data,
    }
}

/// Decode an FFN block (`manifest.k × intermediate_h`) back into a dense
/// `manifest.d × intermediate_h` tensor. Rows outside the standing set
/// stay `0.0`; columns are taken in full.
pub fn decode_ffn_block(
    block: &QuantBlock,
    manifest: &SpectralManifest,
    intermediate_h: u32,
) -> DenseTensor {
    debug_assert!(manifest.is_well_formed());
    let d = manifest.d as usize;
    let k = manifest.k as usize;
    let h = intermediate_h as usize;
    let mut data = vec![0.0f32; d * h];
    let payload = unwrap_fp48_json(&block.payload);
    let scale = read_block_scale(&payload);
    let body = if payload.len() >= SCALE_PREFIX_LEN {
        &payload[SCALE_PREFIX_LEN..]
    } else {
        &[][..]
    };
    let codes = unpack_codes(body, block.bits_per_entry, k * h);
    for local_row in 0..k {
        let global_row = manifest.standing_indices[local_row] as usize;
        if global_row >= d {
            continue;
        }
        let row_base_local = local_row * h;
        let row_base_global = global_row * h;
        for col in 0..h {
            let code = codes[row_base_local + col];
            data[row_base_global + col] = dequantize_signed(code, block.bits_per_entry, scale);
        }
    }
    DenseTensor {
        rows: manifest.d,
        cols: intermediate_h,
        data,
    }
}

// ──────────────────────────────────────────────────────────────────────
// PHASE 3: AMPLITUDE-GRADED DECODER
// ──────────────────────────────────────────────────────────────────────

/// Read a row's worth of `cols` packed codes at `bits` bit-width
/// starting at byte offset `byte_offset`. Returns the codes plus the
/// number of payload bytes consumed (cols × bits, rounded up to a
/// whole byte — graded rows are byte-aligned).
fn unpack_graded_row(
    payload: &[u8],
    byte_offset: usize,
    bits: u8,
    cols: usize,
) -> (Vec<u32>, usize) {
    if bits == 0 || cols == 0 {
        return (vec![0u32; cols], 0);
    }
    let row_bits = cols * bits as usize;
    let row_bytes = row_bits.div_ceil(8);
    let end = (byte_offset + row_bytes).min(payload.len());
    let slice = &payload[byte_offset..end];
    let mut out = Vec::with_capacity(cols);
    let mask = (1u64 << bits) - 1;
    for i in 0..cols {
        let bit_pos = i * bits as usize;
        let byte_idx = bit_pos / 8;
        let bit_offset = bit_pos % 8;
        let mut acc: u64 = 0;
        for b in 0..5 {
            if byte_idx + b < slice.len() {
                acc |= (slice[byte_idx + b] as u64) << (8 * b);
            }
        }
        let code = ((acc >> bit_offset) & mask) as u32;
        out.push(code);
    }
    (out, row_bytes)
}

/// Decode a graded `QuantBlock` produced by
/// [`super::encoder::encode_tensor_graded`]. Reads the `[u8; k]`
/// per-row header, then unpacks each row at its declared bit width
/// (each row begins on a byte boundary).
///
/// Mirrors [`decode_block`] in dimensional shape: off-standing entries
/// stay `0.0`; rows beyond `manifest.d` are skipped.
pub fn decode_block_graded(block: &QuantBlock, manifest: &SpectralManifest) -> DenseTensor {
    debug_assert!(manifest.is_well_formed());
    let d = manifest.d as usize;
    let k = manifest.k as usize;
    let cols = block.cols as usize;
    let mut data = vec![0.0f32; d * d];
    let payload = unwrap_fp48_json(&block.payload);
    let header_len = graded_header_len(manifest.k);
    if payload.len() < SCALE_PREFIX_LEN + header_len {
        return DenseTensor {
            rows: manifest.d,
            cols: manifest.d,
            data,
        };
    }
    let scale = read_block_scale(&payload);
    let row_widths: Vec<u8> = payload[SCALE_PREFIX_LEN..SCALE_PREFIX_LEN + header_len].to_vec();
    // Recover min_width from the header so we can derive each row's
    // effective scale (matching the encoder's `row_scale_for_width`).
    let min_width = row_widths
        .iter()
        .copied()
        .map(|w| w.clamp(GRADED_MIN_BITS, GRADED_MAX_BITS))
        .min()
        .unwrap_or(GRADED_MIN_BITS);
    let mut cursor = SCALE_PREFIX_LEN + header_len;
    for local_row in 0..k {
        let raw_w = row_widths[local_row];
        let w = raw_w.clamp(GRADED_MIN_BITS, GRADED_MAX_BITS);
        let row_scale = row_scale_for_width(scale, min_width, w);
        let (codes, consumed) = unpack_graded_row(&payload, cursor, w, cols);
        cursor += consumed;
        let global_row = manifest.standing_indices[local_row] as usize;
        if global_row >= d {
            continue;
        }
        let row_base_global = global_row * d;
        for local_col in 0..k {
            let global_col = manifest.standing_indices[local_col] as usize;
            if global_col >= d {
                continue;
            }
            let code = codes.get(local_col).copied().unwrap_or(0);
            data[row_base_global + global_col] = dequantize_signed(code, w, row_scale);
        }
    }
    DenseTensor {
        rows: manifest.d,
        cols: manifest.d,
        data,
    }
}

/// FFN-shaped graded decoder: same header convention as
/// [`decode_block_graded`], but the second axis is taken in full.
pub fn decode_ffn_block_graded(
    block: &QuantBlock,
    manifest: &SpectralManifest,
    intermediate_h: u32,
) -> DenseTensor {
    debug_assert!(manifest.is_well_formed());
    let d = manifest.d as usize;
    let k = manifest.k as usize;
    let h = intermediate_h as usize;
    let mut data = vec![0.0f32; d * h];
    let payload = unwrap_fp48_json(&block.payload);
    let header_len = graded_header_len(manifest.k);
    if payload.len() < SCALE_PREFIX_LEN + header_len {
        return DenseTensor {
            rows: manifest.d,
            cols: intermediate_h,
            data,
        };
    }
    let scale = read_block_scale(&payload);
    let row_widths: Vec<u8> = payload[SCALE_PREFIX_LEN..SCALE_PREFIX_LEN + header_len].to_vec();
    let min_width = row_widths
        .iter()
        .copied()
        .map(|w| w.clamp(GRADED_MIN_BITS, GRADED_MAX_BITS))
        .min()
        .unwrap_or(GRADED_MIN_BITS);
    let mut cursor = SCALE_PREFIX_LEN + header_len;
    for local_row in 0..k {
        let raw_w = row_widths[local_row];
        let w = raw_w.clamp(GRADED_MIN_BITS, GRADED_MAX_BITS);
        let row_scale = row_scale_for_width(scale, min_width, w);
        let (codes, consumed) = unpack_graded_row(&payload, cursor, w, h);
        cursor += consumed;
        let global_row = manifest.standing_indices[local_row] as usize;
        if global_row >= d {
            continue;
        }
        let row_base_global = global_row * h;
        for col in 0..h {
            let code = codes.get(col).copied().unwrap_or(0);
            data[row_base_global + col] = dequantize_signed(code, w, row_scale);
        }
    }
    DenseTensor {
        rows: manifest.d,
        cols: intermediate_h,
        data,
    }
}

#[cfg(test)]
mod tests {
    use super::super::encoder::{compute_block_scale, encode_tensor, quantize_signed};
    use super::super::manifest::{stub_first_k_manifest, stub_strided_manifest};
    use super::*;

    fn dense(rows: u32, cols: u32, fill: f32) -> DenseTensor {
        DenseTensor {
            rows,
            cols,
            data: vec![fill; (rows * cols) as usize],
        }
    }

    #[test]
    fn dequantize_inverse_of_quantize_within_bound() {
        // For every code in [0, 2^bits), dequantize → quantize is identity
        // when scale is 1.0 (so the raw signed code lattice is the
        // round-trip target).
        let scale = 1.0_f32;
        for bits in 1u8..=8 {
            let max = (1u32 << bits) - 1;
            for code in 0..=max {
                let x = dequantize_signed(code, bits, scale);
                let round = quantize_signed(x, bits, scale);
                assert_eq!(
                    round, code,
                    "bits={} code={} dequant={} requantized={}",
                    bits, code, x, round
                );
            }
        }
    }

    #[test]
    fn dequantize_zero_bits_is_zero() {
        assert_eq!(dequantize_signed(0, 0, 1.0), 0.0);
        assert_eq!(dequantize_signed(123, 0, 0.5), 0.0);
    }

    #[test]
    fn signed_round_trip_recovers_negative_values() {
        // The bug being fixed: negatives must reconstruct to ~the same
        // negative value, not collapse to 0. Scale at 8 bits over a
        // [-1, 1] range gives ~1/127 step; we tolerate one step.
        let bits: u8 = 8;
        let vals: Vec<f32> = vec![-1.0, -0.5, -0.1, 0.0, 0.1, 0.5, 1.0];
        let scale = compute_block_scale(vals.iter(), bits);
        let tol = scale * 0.6;
        for &v in &vals {
            let code = quantize_signed(v, bits, scale);
            let recovered = dequantize_signed(code, bits, scale);
            assert!(
                (recovered - v).abs() <= tol,
                "v={} recovered={} tol={}",
                v,
                recovered,
                tol
            );
        }
    }

    #[test]
    fn decode_block_dimensions() {
        let t = dense(100, 100, 0.5);
        let m = stub_first_k_manifest(100, 0.30);
        let block = encode_tensor(&t, &m, 4);
        let decoded = decode_block(&block, &m);
        assert_eq!(decoded.rows, m.d);
        assert_eq!(decoded.cols, m.d);
        assert_eq!(decoded.data.len(), (m.d * m.d) as usize);
    }

    #[test]
    fn decode_block_zero_off_standing() {
        // Use strided manifest so off-standing positions are interleaved
        // with standing ones — guards against locality-induced false
        // positives.
        let t = dense(64, 64, 0.5);
        let m = stub_strided_manifest(64, 0.25);
        let block = encode_tensor(&t, &m, 4);
        let decoded = decode_block(&block, &m);
        let standing: std::collections::HashSet<u32> = m.standing_indices.iter().copied().collect();
        for i in 0..m.d {
            for j in 0..m.d {
                if !(standing.contains(&i) && standing.contains(&j)) {
                    assert_eq!(
                        decoded.get(i, j),
                        0.0,
                        "off-standing position ({},{}) should be 0.0",
                        i,
                        j
                    );
                }
            }
        }
    }

    #[test]
    fn decode_block_round_trip_on_standing_subspace() {
        // Round-trip through signed quantization: error is bounded by
        // ~scale (one quantization step). Tolerance = scale * 0.6
        // (slightly above the 0.5-step nyquist to absorb rounding).
        let bits: u8 = 4;
        let d: u32 = 64;
        let m = stub_strided_manifest(d, 0.30);
        // Fill with a deterministic, signed pattern in (-1, 1).
        let mut data = vec![0.0f32; (d * d) as usize];
        for i in 0..d {
            for j in 0..d {
                let idx = (i * d + j) as usize;
                let mag = ((i.wrapping_mul(17) ^ j.wrapping_mul(31)) % 100) as f32 / 100.0;
                let sign = if (i ^ j) & 1 == 0 { 1.0 } else { -1.0 };
                data[idx] = mag * sign;
            }
        }
        let t = DenseTensor {
            rows: d,
            cols: d,
            data,
        };
        let block = encode_tensor(&t, &m, bits);
        let decoded = decode_block(&block, &m);
        let scale = read_block_scale(&block.payload);
        let bound = scale * 0.6_f32;
        for &i in &m.standing_indices {
            for &j in &m.standing_indices {
                let original = t.get(i, j);
                let recovered = decoded.get(i, j);
                let err = (original - recovered).abs();
                assert!(
                    err <= bound,
                    "round-trip error {} at ({},{}): orig={} recovered={} bound={}",
                    err,
                    i,
                    j,
                    original,
                    recovered,
                    bound
                );
            }
        }
    }

    // ──────────────────────────────────────────────────────────────────
    // Phase 3: amplitude-graded round-trip
    // ──────────────────────────────────────────────────────────────────

    fn graded_manifest(d: u32, k: u32, alignments: &[f32]) -> SpectralManifest {
        assert_eq!(alignments.len(), k as usize);
        SpectralManifest {
            d,
            k,
            standing_indices: (0..k).collect(),
            amplitudes: vec![0.5; k as usize],
            phase_alignment: alignments.to_vec(),
        }
    }

    #[test]
    fn graded_round_trip_matches_uniform_when_extra_bits_zero() {
        // With extra_bits=0, the graded path must match the uniform
        // path on every standing entry (modulo the round-trip error
        // bound shared by both encoders, scaled by the per-block
        // scale).
        let bits: u8 = 4;
        let d: u32 = 64;
        let m = stub_strided_manifest(d, 0.30);
        let mut data = vec![0.0_f32; (d * d) as usize];
        for i in 0..d {
            for j in 0..d {
                let idx = (i * d + j) as usize;
                let mag = ((i.wrapping_mul(13) ^ j.wrapping_mul(7)) % 100) as f32 / 100.0;
                let sign = if (i + j) & 1 == 0 { 1.0 } else { -1.0 };
                data[idx] = mag * sign;
            }
        }
        let t = DenseTensor {
            rows: d,
            cols: d,
            data,
        };
        let block = super::super::encoder::encode_tensor_graded(&t, &m, bits, 0);
        let decoded = decode_block_graded(&block, &m);
        let scale = read_block_scale(&block.payload);
        let bound = scale * 0.6_f32;
        for &i in &m.standing_indices {
            for &j in &m.standing_indices {
                let err = (t.get(i, j) - decoded.get(i, j)).abs();
                assert!(
                    err <= bound,
                    "graded uniform round-trip err {} at ({},{})",
                    err,
                    i,
                    j
                );
            }
        }
    }

    #[test]
    fn graded_round_trip_preserves_high_alignment_better() {
        // Mixed alignments: row 0 = 0.0 (4 bits), row k-1 = 1.0 (8
        // bits). High-alignment row's mean reconstruction error must be
        // strictly smaller than the low-alignment row's.
        let d: u32 = 8;
        let k: u32 = 4;
        // Alignments: [0.0, 0.0, 1.0, 1.0]
        let alignments = [0.0_f32, 0.0, 1.0, 1.0];
        let m = graded_manifest(d, k, &alignments);
        // Fill with deterministic values in (0, 1).
        let mut data = vec![0.0_f32; (d * d) as usize];
        for i in 0..d {
            for j in 0..d {
                let idx = (i * d + j) as usize;
                // Strictly inside (0, 1): vary by both axes so each row
                // sees a distinct distribution.
                data[idx] = ((i * 17 + j * 31 + 11) % 97) as f32 / 100.0;
            }
        }
        let t = DenseTensor {
            rows: d,
            cols: d,
            data,
        };

        let block = super::super::encoder::encode_tensor_graded(&t, &m, 4, 4);
        let decoded = decode_block_graded(&block, &m);

        // Mean abs error for low- vs high-alignment rows.
        let mut low_err = 0.0_f32;
        let mut low_n = 0u32;
        let mut high_err = 0.0_f32;
        let mut high_n = 0u32;
        for (local_row, &i) in m.standing_indices.iter().enumerate() {
            let is_high = m.phase_alignment[local_row] > 0.5;
            for &j in &m.standing_indices {
                let err = (t.get(i, j) - decoded.get(i, j)).abs();
                if is_high {
                    high_err += err;
                    high_n += 1;
                } else {
                    low_err += err;
                    low_n += 1;
                }
            }
        }
        let low_mean = low_err / low_n as f32;
        let high_mean = high_err / high_n as f32;
        assert!(
            high_mean < low_mean,
            "high-alignment rows should round-trip more accurately: high_mean={} low_mean={}",
            high_mean,
            low_mean
        );
    }

    #[test]
    fn graded_decoder_zero_off_standing() {
        // Off-standing positions must remain 0.0 — same guarantee as
        // the uniform decoder.
        let d: u32 = 32;
        let m = stub_strided_manifest(d, 0.25);
        // Use the manifest's own phase_alignment (constant 0.7) so
        // every row gets the same width.
        let t = DenseTensor {
            rows: d,
            cols: d,
            data: vec![0.5; (d * d) as usize],
        };
        let block = super::super::encoder::encode_tensor_graded(&t, &m, 4, 4);
        let decoded = decode_block_graded(&block, &m);
        let standing: std::collections::HashSet<u32> = m.standing_indices.iter().copied().collect();
        for i in 0..d {
            for j in 0..d {
                if !(standing.contains(&i) && standing.contains(&j)) {
                    assert_eq!(
                        decoded.get(i, j),
                        0.0,
                        "off-standing ({},{}) should be 0.0",
                        i,
                        j
                    );
                }
            }
        }
    }

    #[test]
    fn graded_ffn_round_trip_zero_off_standing_rows() {
        let d: u32 = 16;
        let h: u32 = 24;
        let m = stub_strided_manifest(d, 0.25);
        let t = DenseTensor {
            rows: d,
            cols: h,
            data: vec![0.5; (d * h) as usize],
        };
        let block = super::super::encoder::encode_ffn_tensor_graded(&t, &m, h, 4, 4);
        let decoded = decode_ffn_block_graded(&block, &m, h);
        let standing: std::collections::HashSet<u32> = m.standing_indices.iter().copied().collect();
        for i in 0..d {
            if !standing.contains(&i) {
                for j in 0..h {
                    assert_eq!(
                        decoded.get(i, j),
                        0.0,
                        "off-standing row {} col {} should be 0.0",
                        i,
                        j
                    );
                }
            }
        }
    }

    #[test]
    fn decode_ffn_block_zero_off_standing_rows() {
        let d: u32 = 32;
        let h: u32 = 48;
        let t = dense(d, h, 0.5);
        let m = stub_strided_manifest(d, 0.25);
        // Encode FFN through encoder::encode_ffn_tensor.
        let block = super::super::encoder::encode_ffn_tensor(&t, &m, h, 4);
        let decoded = decode_ffn_block(&block, &m, h);
        assert_eq!(decoded.rows, d);
        assert_eq!(decoded.cols, h);
        let standing: std::collections::HashSet<u32> = m.standing_indices.iter().copied().collect();
        for i in 0..d {
            if !standing.contains(&i) {
                for j in 0..h {
                    assert_eq!(
                        decoded.get(i, j),
                        0.0,
                        "off-standing row {} col {} should be 0.0",
                        i,
                        j
                    );
                }
            }
        }
    }
}
